import type { CreateOrderInput, OrderStatus } from '../models/order.js';

const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate that a create-order input has at least one item.
 * Throws if validation fails.
 */
export function validateCreateOrderInput(input: CreateOrderInput): void {
  if (input.items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Check whether a status transition is allowed.
 */
export function isValidOrderStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

import type { User } from '../models/user.js';

/**
 * Validate that a user exists. Throws if the user is undefined.
 */
export function validateUserExists(user: User | undefined, userId: string): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate that an email is not already taken by another user.
 * Throws if the email is in use.
 */
export function validateEmailNotTaken(
  existingUserWithEmail: User | undefined,
  email: string,
): void {
  if (existingUserWithEmail) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not taken by a different user during update.
 * Throws if the email is in use by someone else.
 */
export function validateEmailNotTakenByOther(
  existingUserWithEmail: User | undefined,
  email: string,
): void {
  if (existingUserWithEmail) {
    throw new Error(`Email ${email} is already in use`);
  }
}

