import { describe, it, expect } from 'vitest';
import {
  validateCreateOrderInput,
  isValidOrderStatusTransition,
} from '../../src/validators/order.validator.js';
import type { OrderStatus } from '../../src/models/order.js';

describe('order.validator', () => {
  describe('validateCreateOrderInput', () => {
    it('should pass when items are present', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        }),
      ).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() =>
        validateCreateOrderInput({ userId: 'user-1', items: [] }),
      ).toThrow('Order must have at least one item');
    });
  });

  describe('isValidOrderStatusTransition', () => {
    const validTransitions: [OrderStatus, OrderStatus][] = [
      ['pending', 'confirmed'],
      ['pending', 'cancelled'],
      ['confirmed', 'shipped'],
      ['confirmed', 'cancelled'],
      ['shipped', 'delivered'],
    ];

    for (const [from, to] of validTransitions) {
      it(`should allow ${from} -> ${to}`, () => {
        expect(isValidOrderStatusTransition(from, to)).toBe(true);
      });
    }

    const invalidTransitions: [OrderStatus, OrderStatus][] = [
      ['pending', 'shipped'],
      ['pending', 'delivered'],
      ['confirmed', 'pending'],
      ['shipped', 'cancelled'],
      ['delivered', 'pending'],
      ['delivered', 'cancelled'],
      ['cancelled', 'pending'],
      ['cancelled', 'confirmed'],
    ];

    for (const [from, to] of invalidTransitions) {
      it(`should reject ${from} -> ${to}`, () => {
        expect(isValidOrderStatusTransition(from, to)).toBe(false);
      });
    }
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateUserExists,
  validateEmailNotTaken,
  validateEmailNotTakenByOther,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides: Partial<User> = {}): User => ({
  id: 'user-1',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user.validator', () => {
  describe('validateUserExists', () => {
    it('should pass when user exists', () => {
      expect(() => validateUserExists(makeUser(), 'user-1')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-99')).toThrow(
        'User not found: user-99',
      );
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should pass when no existing user has the email', () => {
      expect(() =>
        validateEmailNotTaken(undefined, 'new@example.com'),
      ).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      expect(() =>
        validateEmailNotTaken(makeUser(), 'alice@example.com'),
      ).toThrow('User with email alice@example.com already exists');
    });
  });

  describe('validateEmailNotTakenByOther', () => {
    it('should pass when no other user has the email', () => {
      expect(() =>
        validateEmailNotTakenByOther(undefined, 'new@example.com'),
      ).not.toThrow();
    });

    it('should throw when email is in use by another user', () => {
      expect(() =>
        validateEmailNotTakenByOther(makeUser(), 'alice@example.com'),
      ).toThrow('Email alice@example.com is already in use');
    });
  });
});

